"""RBAC data models for Grantwise permission system."""
from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional, List, Set, Dict


class PermissionEffect(Enum):
    """Whether a permission rule allows or denies access."""
    ALLOW = "allow"
    DENY = "deny"


@dataclass
class Permission:
    """A single permission rule.

    Attributes:
        resource: Resource identifier (e.g., 'grant:*', 'grant:12345', 'institution:MIT')
        action: Action being permitted/denied (e.g., 'read', 'write', 'delete', 'admin')
        effect: Whether this rule allows or denies the action
    """
    resource: str
    action: str
    effect: PermissionEffect = PermissionEffect.ALLOW

    def matches_resource(self, target_resource: str) -> bool:
        """Check if this permission applies to the target resource.

        Supports wildcard matching:
        - 'grant:*' matches 'grant:12345'
        - 'grant:12345' matches 'grant:12345' exactly
        - '*' matches everything
        """
        if self.resource == '*':
            return True
        if '*' in self.resource:
            prefix = self.resource.split('*')[0]
            return target_resource.startswith(prefix)
        return self.resource == target_resource


@dataclass
class Role:
    """A role with permissions and optional parent roles for inheritance.

    Attributes:
        name: Unique role identifier
        description: Human-readable description
        permissions: Direct permissions assigned to this role
        parent_roles: Parent roles from which permissions are inherited
        priority: Role priority for conflict resolution (higher = more authoritative)
    """
    name: str
    description: str = ""
    permissions: List[Permission] = field(default_factory=list)
    parent_roles: List[str] = field(default_factory=list)
    priority: int = 0

    def get_direct_permissions(self, action: str, resource: str) -> List[Permission]:
        """Get permissions from this role that match the given action and resource."""
        return [
            p for p in self.permissions
            if p.action == action and p.matches_resource(resource)
        ]


@dataclass
class UserRoleAssignment:
    """Assignment of a role to a user, optionally scoped to a resource."""
    user_id: str
    role_name: str
    resource_scope: Optional[str] = None  # If set, role only applies to this resource


@dataclass
class RoleRegistry:
    """Registry holding all defined roles."""
    _roles: Dict[str, Role] = field(default_factory=dict)

    def register(self, role: Role) -> None:
        self._roles[role.name] = role

    def get(self, name: str) -> Optional[Role]:
        return self._roles.get(name)

    def get_all(self) -> Dict[str, Role]:
        return dict(self._roles)

    def get_parent_roles(self, role_name: str) -> List[Role]:
        """Get the parent Role objects for a given role name."""
        role = self._roles.get(role_name)
        if not role:
            return []
        return [self._roles[p] for p in role.parent_roles if p in self._roles]

"""Tests for the RBAC permission evaluator."""
import pytest
from rbac.models import (
    Permission,
    PermissionEffect,
    Role,
    RoleRegistry,
    UserRoleAssignment,
)
from rbac.evaluator import PermissionEvaluator


@pytest.fixture
def registry():
    """Create a role registry with standard Grantwise roles."""
    reg = RoleRegistry()

    # Base viewer role
    viewer = Role(
        name="viewer",
        description="Read-only access to grants",
        permissions=[
            Permission(resource="grant:*", action="read", effect=PermissionEffect.ALLOW),
        ],
    )
    reg.register(viewer)

    # Editor inherits from viewer, adds write
    editor = Role(
        name="editor",
        description="Can edit grants",
        permissions=[
            Permission(resource="grant:*", action="write", effect=PermissionEffect.ALLOW),
        ],
        parent_roles=["viewer"],
    )
    reg.register(editor)

    # Admin role with full access
    admin = Role(
        name="admin",
        description="Full administrative access",
        permissions=[
            Permission(resource="*", action="read", effect=PermissionEffect.ALLOW),
            Permission(resource="*", action="write", effect=PermissionEffect.ALLOW),
            Permission(resource="*", action="delete", effect=PermissionEffect.ALLOW),
            Permission(resource="*", action="admin", effect=PermissionEffect.ALLOW),
        ],
    )
    reg.register(admin)

    # Restricted viewer: can view but explicitly denied write
    restricted_viewer = Role(
        name="restricted_viewer",
        description="View-only, explicitly denied write",
        permissions=[
            Permission(resource="grant:*", action="read", effect=PermissionEffect.ALLOW),
            Permission(resource="grant:*", action="write", effect=PermissionEffect.DENY),
        ],
    )
    reg.register(restricted_viewer)

    # Department lead - inherits from editor
    dept_lead = Role(
        name="dept_lead",
        description="Department lead with extra reporting",
        permissions=[
            Permission(resource="report:*", action="read", effect=PermissionEffect.ALLOW),
        ],
        parent_roles=["editor"],
    )
    reg.register(dept_lead)

    return reg


@pytest.fixture
def evaluator(registry):
    return PermissionEvaluator(registry)


class TestDirectPermissions:
    """Test permissions directly assigned to a role (no inheritance)."""

    def test_allow_read_grant(self, evaluator):
        assignments = [UserRoleAssignment(user_id="user1", role_name="viewer")]
        assert evaluator.evaluate("user1", "read", "grant:12345", assignments) is True

    def test_deny_write_for_viewer(self, evaluator):
        assignments = [UserRoleAssignment(user_id="user1", role_name="viewer")]
        assert evaluator.evaluate("user1", "write", "grant:12345", assignments) is False

    def test_admin_has_full_access(self, evaluator):
        assignments = [UserRoleAssignment(user_id="admin1", role_name="admin")]
        assert evaluator.evaluate("admin1", "delete", "grant:99999", assignments) is True
        assert evaluator.evaluate("admin1", "admin", "institution:MIT", assignments) is True

    def test_no_assignments_denied(self, evaluator):
        assert evaluator.evaluate("user1", "read", "grant:12345", []) is False


class TestSingleLevelInheritance:
    """Test permission inheritance from parent roles (1 level)."""

    def test_editor_inherits_read(self, evaluator):
        assignments = [UserRoleAssignment(user_id="user1", role_name="editor")]
        assert evaluator.evaluate("user1", "read", "grant:12345", assignments) is True

    def test_editor_has_write(self, evaluator):
        assignments = [UserRoleAssignment(user_id="user1", role_name="editor")]
        assert evaluator.evaluate("user1", "write", "grant:12345", assignments) is True

    def test_editor_no_delete(self, evaluator):
        assignments = [UserRoleAssignment(user_id="user1", role_name="editor")]
        assert evaluator.evaluate("user1", "delete", "grant:12345", assignments) is False


class TestDenyOverride:
    """Test that deny rules override allow rules."""

    def test_explicit_deny_blocks_write(self, evaluator):
        assignments = [UserRoleAssignment(user_id="user1", role_name="restricted_viewer")]
        assert evaluator.evaluate("user1", "write", "grant:12345", assignments) is False

    def test_explicit_deny_still_allows_read(self, evaluator):
        assignments = [UserRoleAssignment(user_id="user1", role_name="restricted_viewer")]
        assert evaluator.evaluate("user1", "read", "grant:12345", assignments) is True


class TestTwoLevelInheritance:
    """Test permission inheritance through two levels of hierarchy."""

    def test_dept_lead_inherits_read_from_viewer(self, evaluator):
        assignments = [UserRoleAssignment(user_id="user1", role_name="dept_lead")]
        assert evaluator.evaluate("user1", "read", "grant:12345", assignments) is True

    def test_dept_lead_inherits_write_from_editor(self, evaluator):
        assignments = [UserRoleAssignment(user_id="user1", role_name="dept_lead")]
        assert evaluator.evaluate("user1", "write", "grant:12345", assignments) is True

    def test_dept_lead_has_report_access(self, evaluator):
        assignments = [UserRoleAssignment(user_id="user1", role_name="dept_lead")]
        assert evaluator.evaluate("user1", "read", "report:annual", assignments) is True


class TestResourceScoping:
    """Test resource-scoped role assignments."""

    def test_scoped_role_allows_matching_resource(self, evaluator):
        assignments = [
            UserRoleAssignment(user_id="user1", role_name="editor", resource_scope="grant:12345")
        ]
        assert evaluator.evaluate("user1", "write", "grant:12345", assignments) is True

    def test_scoped_role_denies_non_matching_resource(self, evaluator):
        assignments = [
            UserRoleAssignment(user_id="user1", role_name="editor", resource_scope="grant:12345")
        ]
        assert evaluator.evaluate("user1", "write", "grant:99999", assignments) is False

